@js:
id=java.get("id")
if (/baidu\.com/.test(baseUrl)) {
    pre = baseUrl.replace(/baidu\.com/, "biquge.casa");
    rev = org.jsoup.Jsoup.parse(java.ajax(pre));
    url = source.key + "/" + id +  rev.select('#linkPrev').attr('href');
    java.setContent(result = java.ajax(url));
} else if (/bing\.com/.test(baseUrl)) {
    nex = baseUrl.replace(/cn\.bing\.com/, "www.biquge.casa");
    next = org.jsoup.Jsoup.parse(java.ajax(nex));
    nexUrl = source.key + "/" + id +  next.select('#linkNext').attr('href');
    java.setContent(result = java.ajax(nexUrl));
  } else { result; }
result = java.getString('.readcontent@html');

